using UnityEngine;
using System;

namespace RoboIguanaRL {

    /// <summary>
    /// Provides Acces to experimental data about the tail of RoboIguana.
    /// </summary>
    public class TailManager: MonoBehaviour
    {
        [Header("Tail Force Point")]
        public SimpleForcePoint forcePoint;

        /// <summary>
        /// Current forces (x,y,z) generated by the tail.
        /// </summary>
        public Vector3 Force; 

        /// <summary>
        /// Cuurent energy consuption by the tail.
        /// </summary>
        public float EnergyConsumption;

        /// <summary>
        /// Current control parameters of the tail.
        /// </summary>
        public float[] parameters;

        // ######################
        // internal stuff
        // ######################

        /// <summary>
        /// Control parameters to choose from.
        /// </summary>
        private readonly float[][] possibleParameters = new float[][]
        {
            new float[] {0f, 0.5f, 0.75f, 1f},      // Frequencies
            new float[] {20f, 30f, 40f},            // Sway Ampls
            new float[] {0f, 10f, 20f, 30f, 40f}    // yaw Amps
        };

        /// <summary>
        /// Phase lag from sway to yaw in the tail. 270 found as optimal value by experiment
        /// </summary>
        private const float DefaultPhaseLag = 270f;

        /// <summary>
        /// Marks progress of the tail cycle. Progress is calculated from frequency.
        /// </summary>
        public float phase;

        /// <summary>
        /// Frequency of tail cycles.
        /// </summary>
        public float frequency;

        /// <summary>
        /// Ampltude of sway in the tail base.
        /// </summary>
        public float swayAmplitude;

        /// <summary>
        /// Ampltude of yaw in the tail.
        /// </summary>
        public float yawAmplitude;

        /// <summary>
        /// Indices of applied control parameters.
        /// </summary>
        private int[] ParamIdcs;

        /// <summary>
        /// Time step between physics steps.
        /// </summary>
        private float TimeStep;

        /// <summary>
        /// Initializes the tail.
        /// </summary>
        public void Initialize()
        {
            TimeStep  = Time.fixedDeltaTime;
            parameters = new float[] {frequency, swayAmplitude, yawAmplitude};
            Reset();
        }

        /// <summary>
        /// Resets state of the tail.
        /// </summary>
        public void Reset()
        {
            ParamIdcs = new int[] {0, 0, 0};
            Force = Vector3.zero;
            EnergyConsumption = 0f;
            phase = 0f;
        }

        /// <summary>
        /// Calculates the forces generated by the tail.
        /// </summary>
        public void CalculateForces()
        {
            // return;
            Force.x = 0f;
            Force.y = 0f;
            Force.z = 0f;
        }

        /// <summary>
        /// Calculates the energy consumed by the tail.
        /// </summary>
        public void CalculateEnergyConsuption()
        {
            return;
        }

        /// <summary>
        /// Sets generated forces and consumed energy according to current parameters.
        /// </summary>
        public void FixedUpdate()
        {
            phase = Mathf.Clamp(phase +  frequency * TimeStep, 0, 2 * Mathf.PI);
            
            CalculateForces();
            CalculateEnergyConsuption();

            forcePoint.ApplyLocalForce(Force);
        }

        /// <summary>
        /// Apply input changes to control parameters.
        /// </summary>
        /// <param name="changes"></param>
        public void UpdateParameters(int[] changes)
        {
            for (int i = 0; i < parameters.Length; i++)
            {
                ParamIdcs[i] = Math.Clamp(ParamIdcs[i] + changes[i], 0, possibleParameters[i].Length);
                parameters[i] = possibleParameters[i][ParamIdcs[i]];
            }       
            // prevent f==1, r_sway == 40 for mechanical reasons   
            if (parameters[0] * parameters[1] == 40) {
                parameters[0] = 0.75f;  
                ParamIdcs[0] -= 1;
            }
        }

    }
}